class Solution:
    def checkValidGrid(self, grid):
        n = len(grid)
        if grid[0][0] != 0:
            return False
        def find(v):
            for i in range(n):
                for j in range(n):
                    if grid[i][j] == v:
                        return i, j
            return None
        for k in range(n * n - 1):
            r1, c1 = find(k)
            r2, c2 = find(k + 1)
            if sorted([abs(r1 - r2), abs(c1 - c2)]) != [1, 2]:
                return False
        return True

