class Solution:
    def checkValidGrid(self, grid):
        n = len(grid)
        if grid[0][0] != 0:
            return False
        pos = {}
        for i in range(n):
            for j in range(n):
                pos[grid[i][j]] = (i, j)
        for k in range(n * n - 1):
            r1, c1 = pos[k]
            r2, c2 = pos[k + 1]
            dr, dc = abs(r1 - r2), abs(c1 - c2)
            if not ((dr == 1 and dc == 2) or (dr == 2 and dc == 1)):
                return False
        return True

