var checkValidGrid = function(grid) {
    const n = grid.length;
    if (grid[0][0] !== 0) return false;
    const pos = new Array(n * n);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            pos[grid[i][j]] = [i, j];
        }
    }
    for (let k = 0; k < n * n - 1; k++) {
        const [r1, c1] = pos[k];
        const [r2, c2] = pos[k + 1];
        const dr = Math.abs(r1 - r2), dc = Math.abs(c1 - c2);
        if (!((dr === 1 && dc === 2) || (dr === 2 && dc === 1))) return false;
    }
    return true;
};
